const req = $('Webhook: URL Submit').item.json.body;
const scrapeItem = $input.item.json;
let productCtx = '';

const raw = typeof scrapeItem.data === 'string' ? scrapeItem.data
          : typeof scrapeItem.body === 'string' ? scrapeItem.body : '';

if (raw.length > 200) {
  const nextDataMatch = raw.match(/<script[^>]+id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/);
  if (nextDataMatch) {
    try {
      const nd = JSON.parse(nextDataMatch[1]);
      const pp = nd?.props?.pageProps || {};
      const m = pp.model || pp.modelDetail || pp.modelInfo || {};
      const stats = m.summary || m.stat || {};
      const creator = m.user || m.designer || {};
      productCtx = 'SOURCE URL: ' + req.url + '\n\nSTRUCTURED DATA FROM PAGE:\n' + JSON.stringify({
        title: m.name || m.title || pp.title,
        description: m.description || m.summary,
        author: creator.name || creator.handle || creator.username,
        category: m.category || m.type,
        likes: stats.likeCount || stats.like || m.likeCount,
        downloads: stats.downloadCount || stats.download || m.downloadCount,
        makes: stats.makeCount || stats.make || m.makeCount,
        printTime: m.printTime || m.estimatedTime,
        filament: m.filamentUsed || m.filament
      }, null, 2);
    } catch (e) {}
  }
  if (!productCtx) {
    const text = raw
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<!--[\s\S]*?-->/g, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
      .replace(/\s{2,}/g, ' ').trim().substring(0, 5000);
    productCtx = 'SOURCE URL: ' + req.url + '\n\nSCRAPED TEXT:\n' + text;
  }
} else {
  productCtx = 'SOURCE URL: ' + req.url + '\n(Page returned minimal content)';
}

return [{ json: { productContext: productCtx } }];

const body = $json.body;

if (body.productContext) {
  return [{ json: { productContext: body.productContext, originalRequest: body } }];
}

if (body.description) {
  return [{ json: { productContext: 'PRODUCT IDEA (free text): "' + body.description + '"', originalRequest: body } }];
}

return [{ json: { productContext: '', originalRequest: body } }];

